module sr_latch (
    input wire S,
    input wire R,
    output reg obf_Q,
    output reg Qn
);
    always @ (S or R) begin
        if (S && !R) begin
            obf_Q <= 1'b1;
            Qn <= 1'b0;
        end else if (!S && R) begin
            obf_Q <= 1'b0;
            Qn <= 1'b1;
        end else if (!S && !R) begin
            // Retain previous state
            obf_Q <= obf_Q;
            Qn <= Qn;
        end else begin
            // Invalid state when both S and R are high
            obf_Q <= 1'bx;
            Qn <= 1'bx;
        end
    end
endmodule
